import{_ as n,o as a,c as e,S as t}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"面试官问：MCP 协议是什么？和 A2A 协议有什么区别？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_18-mcp.md","filePath":"面试官问/17ai/q_ai_18-mcp.md","lastUpdated":1778207238000}'),p={name:"面试官问/17ai/q_ai_18-mcp.md"};function l(r,s,i,o,c,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="面试官问-mcp-协议是什么-和-a2a-协议有什么区别" tabindex="-1">面试官问：MCP 协议是什么？和 A2A 协议有什么区别？ <a class="header-anchor" href="#面试官问-mcp-协议是什么-和-a2a-协议有什么区别" aria-label="Permalink to &quot;面试官问：MCP 协议是什么？和 A2A 协议有什么区别？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_27-mcp.html">MCP 协议</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_24-agent.html">AI Agent 智能体</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_29-multi_agent.html">Multi-Agent 系统</a></p></blockquote><h2 id="_1-mcp-协议是什么-和-a2a-协议有什么区别" tabindex="-1">1. MCP 协议是什么？和 A2A 协议有什么区别？ <a class="header-anchor" href="#_1-mcp-协议是什么-和-a2a-协议有什么区别" aria-label="Permalink to &quot;1. MCP 协议是什么？和 A2A 协议有什么区别？&quot;">​</a></h2><p><strong>考察点</strong>：是否理解 MCP 协议的核心定位（统一工具接口），能否区分 MCP（模型↔工具）和 A2A（Agent↔Agent）的适用场景。</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p><strong>MCP</strong>（Model Context Protocol）是 Anthropic 开源的标准协议，定义了大模型与外部工具/数据源之间的统一交互方式。简单理解：<strong>MCP 是 AI 世界的&quot;USB-C 接口&quot;</strong>。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>MCP 架构：</span></span>
<span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  MCP Host（AI 应用，如 Claude Desktop）   │</span></span>
<span class="line"><span>│       ↕ MCP Protocol                    │</span></span>
<span class="line"><span>│  MCP Client（协议客户端）                 │</span></span>
<span class="line"><span>│       ↕ 标准 JSON-RPC                   │</span></span>
<span class="line"><span>│  MCP Server（工具/数据提供方）            │</span></span>
<span class="line"><span>│    ├── 文件系统 Server                   │</span></span>
<span class="line"><span>│    ├── 数据库 Server                     │</span></span>
<span class="line"><span>│    ├── Web 搜索 Server                   │</span></span>
<span class="line"><span>│    └── 自定义业务 Server                 │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>三大核心概念</strong>：</p><ul><li>📦 <strong>Resources</strong>：暴露数据（类似 GET 请求 —— 读取文件、数据库查询结果）</li><li>🔧 <strong>Tools</strong>：暴露操作（类似 POST 请求 —— 创建文件、发送消息）</li><li>📝 <strong>Prompts</strong>：预定义提示词模板</li></ul><p><strong>MCP vs A2A 协议对比</strong>：</p><table><thead><tr><th>维度</th><th>MCP (Model Context Protocol)</th><th>A2A (Agent-to-Agent)</th></tr></thead><tbody><tr><td><strong>提出方</strong></td><td>Anthropic</td><td>Google</td></tr><tr><td><strong>核心场景</strong></td><td>模型 ↔ 工具/数据</td><td>Agent ↔ Agent</td></tr><tr><td><strong>交互模式</strong></td><td>Client → Server 请求-响应</td><td>Agent 间对等通信 + 任务委派</td></tr><tr><td><strong>类比</strong></td><td>USB-C 接口（统一外设连接）</td><td>微服务间通信协议</td></tr><tr><td><strong>传输层</strong></td><td>stdio / HTTP-SSE</td><td>gRPC / HTTP</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>MCP 解决什么问题：</span></span>
<span class="line"><span>├── 之前：每个 AI 应用都要单独开发 OAuth、文件系统、数据库集成</span></span>
<span class="line"><span>├── 现在：一次开发 MCP Server，所有 AI 应用都能用</span></span>
<span class="line"><span>└── 类比：就像 USB-C 统一了充电接口，MCP 统一了 AI 工具接口</span></span>
<span class="line"><span></span></span>
<span class="line"><span>A2A 解决什么问题：</span></span>
<span class="line"><span>├── MCP 是&quot;模型怎么用工具&quot;，A2A 是&quot;Agent 之间怎么协作&quot;</span></span>
<span class="line"><span>├── 场景：Agent A 做前端开发，Agent B 做测试</span></span>
<span class="line"><span>│        Agent C 做代码审查 → 三个 Agent 通过 A2A 协作</span></span>
<span class="line"><span>└── 可以理解为：MCP 是垂直协议（模型↔工具），A2A 是水平协议（智能体↔智能体）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>前端关注点</strong>：</p><ul><li>MCP 是构建 AI 原生应用的关键协议</li><li>前端可以扮演 MCP Client 角色（Web 应用中集成 MCP 工具）</li><li>了解 MCP 有助于理解 AI 应用架构的未来趋势</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>MCP = 统一工具接口标准（USB-C 类比）</li><li>区分 MCP（模型↔工具）和 A2A（Agent↔Agent）</li><li>知道三种客户端-服务器传输方式：stdio、HTTP-SSE、WebSocket</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_27-mcp.html">MCP 协议概念讲解</a></p></blockquote>`,6)])])}const g=n(p,[["render",l]]);export{u as __pageData,g as default};
